#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_reduce_identity() {
        for x in [0u64, 1, 2147483646, 2147483647, 2147483648, u64::MAX >> 1] {
            assert_eq!(
                Mersenne31::reduce(x) % MERSENNE31_P,
                x % MERSENNE31_P,
                "reduce failed"
            );
        }
    }

    #[test]
    fn test_butterfly_roundtrip() {
        let a = 42u64;
        let w = 7u64;
        let b = 99u64;
        let sum = Mersenne31::butterfly_sum(a, w, b);
        assert_eq!(sum % MERSENNE31_P, (a + w * b) % MERSENNE31_P);
    }
}
